// src/App/TaskCard.jsx
import React, { useState } from 'react';
import '../../styles/Windows/StyleTaskCard.css'; // Базовые стили карточки
import '../../styles/Buttons/StyleAddTaskButton.css'; // Стили для анимации кнопок (btn-bg-slide)
import '../../styles/Windows/StyleTaskDescriptionModal.css'; // Стили для кнопки "Описание" и окна деталей
import TaskDescriptionModal from './UserTaskListComponents/TaskDescriptionModal'; // Компонент модального окна

export default function TaskCard({ task, onEdit, onDelete }) {

    // Состояние для управления открытием окна с описанием
    const [isDescOpen, setIsDescOpen] = useState(false);

    // Функция форматирования даты
    const formatDate = (dateString) => {
        if (!dateString) return '';
        const date = new Date(dateString);
        return date.toLocaleDateString('ru-RU', {
            day: 'numeric',
            month: 'short',
            year: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    // Определение цвета приоритета
    const getPriorityColor = (p) => {
        if (p === 'high') return '#ff5252';   // Красный
        if (p === 'medium') return '#ffd60a'; // Желтый
        if (p === 'low') return '#38ef7d';    // Зеленый
        return 'rgba(255,255,255,0.3)';       // Серый (по умолчанию)
    };

    const priorityColor = getPriorityColor(task.priority);

    return (
        <>
            {/* --- КАРТОЧКА ЗАДАЧИ --- */}
            <div className="task-card glass-panel">

                {/* Верхняя часть: Заголовок и значок важности */}
                <div className="task-header">
                    <h3>{task.title}</h3>
                    <div
                        className="priority-badge"
                        style={{ backgroundColor: priorityColor }}
                        title={`Важность: ${task.priority}`}
                    ></div>
                </div>

                {/* КНОПКА "ОПИСАНИЕ" (вместо самого текста описания) */}
                <div className="task-desc-trigger">
                    <button
                        className="btn-desc-small"
                        onClick={() => setIsDescOpen(true)}
                    >
                        <span className="btn-text">Описание</span>
                        {/* Иконка документа/информации */}
                        <img src="https://img.icons8.com/?size=96&id=11865&format=png" alt="Info" className="btn-icon" />
                        <div className="btn-bg-slide desc-bg"></div>
                    </button>
                </div>

                {/* Нижняя часть: Даты и Кнопки действий */}
                <div className="task-footer">
                    <div className="task-dates">
                        <span className="task-date-label">Создано:&nbsp;</span>
                        <span className="date-value">{formatDate(task.createdAt)}</span>

                        {task.deadline && (
                            <>
                                <span className="date-separator">&nbsp;—&nbsp;</span>
                                <span className="task-date-label">Дедлайн:&nbsp;</span>
                                <span className="date-value">{formatDate(task.deadline)}</span>
                            </>
                        )}
                    </div>

                    <div className="task-actions">
                        <button className="icon-btn" onClick={() => onEdit(task)}>
                            <img src="https://img.icons8.com/?size=96&id=TGKHLKPBB4J8&format=png" alt="Изменить" />
                        </button>
                        <button className="icon-btn" onClick={() => onDelete(task)}>
                            <img src="https://img.icons8.com/?size=96&id=CzTISLkmHrKE&format=png" alt="Удалить" />
                        </button>
                    </div>
                </div>
            </div>

            {/* --- МОДАЛЬНОЕ ОКНО С ОПИСАНИЕМ --- */}
            <TaskDescriptionModal
                task={task}
                isOpen={isDescOpen}
                onClose={() => setIsDescOpen(false)}
            />
        </>
    );
}
